 99→func (a *Agent) ensureCachedTranscript(cwd string, sessionID string) (string, error) {
100→	db, err := kiroCLIDataDBPath()
101→	if err != nil {
102→		return "", err
103→	}
104→	if _, err := os.Stat(db); err != nil {
105→		return "", fmt.Errorf("kiro database not found at %s: %w", db, err)
106→	}
107→
108→	query := fmt.Sprintf(
109→		"SELECT value FROM conversations_v2 WHERE key = '%s' ORDER BY updated_at DESC LIMIT 1",
110→		escapeSQLString(cwd),
111→	)
112→
113→	out, err := runSQLiteCommand(db, query)
114→	if err != nil {
115→		return "", fmt.Errorf("sqlite3 transcript query failed: %w", err)
116→	}
117→
118→	transcript := strings.TrimSpace(string(out))
119→	if transcript == "" {
120→		return "", errors.New("no transcript found")
121→	}
122→
123→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
124→	if err != nil {
125→		return "", err
126→	}
127→	if err := os.WriteFile(cachePath, []byte(transcript), 0o600); err != nil {
128→		return "", fmt.Errorf("failed to write cached transcript: %w", err)
129→	}
130→	return cachePath, nil
131→}
