282→func (a *Agent) ExtractPrompts(path string, offset int) ([]string, error) {
283→	transcript, err := readAndParseTranscript(path)
284→	if errors.Is(err, os.ErrNotExist) {
285→		return nil, nil
286→	}
287→	if err != nil {
288→		return nil, err
289→	}
290→
291→	var prompts []string
292→	for i := offset; i < len(transcript.History); i++ {
293→		if prompt := extractUserPrompt(transcript.History[i].User.Content); prompt != "" {
294→			prompts = append(prompts, prompt)
