 32→type ideHookDef struct {
 33→	Filename    string
 34→	TriggerType string
 35→	CLIVerb     string
 36→}
 37→
 38→var ideHookDefs = []ideHookDef{
 39→	{Filename: "entire-prompt-submit", TriggerType: "promptSubmit", CLIVerb: HookNameUserPromptSubmit},
 40→	{Filename: "entire-stop", TriggerType: "agentStop", CLIVerb: HookNameStop},
 41→	{Filename: "entire-pre-tool-use", TriggerType: "preToolUse", CLIVerb: HookNamePreToolUse},
 42→	{Filename: "entire-post-tool-use", TriggerType: "postToolUse", CLIVerb: HookNamePostToolUse},
