170→	file := kiroAgentFile{
171→		Name: "entire",
172→		Tools: []string{
173→			"read", "write", "shell", "grep", "glob",
174→			"aws", "report", "introspect", "knowledge",
175→			"thinking", "todo", "delegate",
176→		},
177→		Hooks: kiroHooks{
178→			AgentSpawn:       []kiroHookEntry{{Command: commandBase + HookNameAgentSpawn}},
179→			UserPromptSubmit: []kiroHookEntry{{Command: commandBase + HookNameUserPromptSubmit}},
180→			PreToolUse:       []kiroHookEntry{{Command: commandBase + HookNamePreToolUse}},
181→			PostToolUse:      []kiroHookEntry{{Command: commandBase + HookNamePostToolUse}},
182→			Stop:             []kiroHookEntry{{Command: commandBase + HookNameStop}},
