273→func trustedCommandsPresent(repoRoot string, localDev bool) bool {
274→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
275→	data, err := os.ReadFile(settingsPath)
276→	if err != nil {
277→		return false
278→	}
279→	var settings map[string]json.RawMessage
280→	if err := json.Unmarshal(data, &settings); err != nil {
281→		return false
282→	}
283→	raw, ok := settings[trustedCommandsKey]
284→	if !ok {
285→		return false
286→	}
287→	var commands []string
288→	if err := json.Unmarshal(raw, &commands); err != nil {
289→		return false
290→	}
291→	want := trustedCommand(localDev)
292→	for _, command := range commands {
293→		if command == want {
294→			return true
295→		}
296→	}
297→	return false
298→}
