360→func hookCommandBase(localDev bool) string {
361→	if localDev {
362→		return localDevCommandBase
363→	}
364→	return prodHookCommandBase
365→}
366→
367→// shellWrappedCommand wraps a hook command in "sh -c" with a /dev/null stdin
368→// redirect. IDEs typically run hook commands directly without a shell, so a
369→// bare "</dev/null" suffix is passed as a literal argument instead of being
370→// interpreted as a redirect. Wrapping in sh ensures the redirect works.
371→// The command content is built from compile-time constants (not user input).
372→func shellWrappedCommand(cmd string) string {
373→	return "sh -c '" + cmd + " </dev/null'"
374→}
375→
376→func trustedCommand(localDev bool) string {
377→	if localDev {
378→		return localDevTrustedCmd
379→	}
380→	return prodTrustedCommand
381→}
