383→func readSettings(path string) (map[string]json.RawMessage, error) {
384→	data, err := os.ReadFile(path)
385→	if err != nil {
386→		if os.IsNotExist(err) {
387→			return map[string]json.RawMessage{}, nil
388→		}
389→		return nil, err
390→	}
391→	var settings map[string]json.RawMessage
392→	if err := json.Unmarshal(data, &settings); err != nil {
393→		return nil, err
394→	}
395→	if settings == nil {
396→		settings = map[string]json.RawMessage{}
397→	}
398→	return settings, nil
399→}
400→
401→func readTrustedCommands(settings map[string]json.RawMessage) ([]string, error) {
402→	raw, ok := settings[trustedCommandsKey]
403→	if !ok {
404→		return []string{}, nil
405→	}
406→	var commands []string
407→	if err := json.Unmarshal(raw, &commands); err != nil {
408→		return nil, err
409→	}
410→	return commands, nil
411→}
412→
413→func writeSettings(path string, settings map[string]json.RawMessage) error {
414→	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
415→		return err
416→	}
417→	data, err := marshalJSON(settings)
418→	if err != nil {
419→		return err
420→	}
421→	return os.WriteFile(path, data, 0o600)
422→}
423→
424→func marshalJSON(v any) ([]byte, error) {
425→	data, err := json.MarshalIndent(v, "", "  ")
426→	if err != nil {
427→		return nil, err
428→	}
429→	return append(data, '\n'), nil
430→}
