220→	if err != nil {
221→		return err
222→	}
223→	event, err := parser.ParseHook(*hook, input)
224→	if err != nil {
225→		return err
226→	}
227→	if event == nil {
228→		_, err = io.WriteString(stdout, "null\n")
229→		return err
230→	}
231→	return WriteJSON(stdout, event)
232→}
