 30→// AssertFileExists asserts that at least one file matches the glob pattern
 31→// relative to dir.
 32→func AssertFileExists(t *testing.T, dir string, glob string) {
 33→	t.Helper()
 34→	matches, err := filepath.Glob(filepath.Join(dir, glob))
