 37→func (a *Agent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
 38→	if maxSize <= 0 {
 39→		return nil, errors.New("max-size must be greater than zero")
 40→	}
 41→	if len(content) == 0 {
 42→		return [][]byte{[]byte{}}, nil
 43→	}
 44→
 45→	var chunks [][]byte
 46→	for start := 0; start < len(content); start += maxSize {
 47→		end := start + maxSize
 48→		if end > len(content) {
 49→			end = len(content)
 50→		}
 51→		chunk := make([]byte, end-start)
 52→		copy(chunk, content[start:end])
 53→		chunks = append(chunks, chunk)
 54→	}
 55→	return chunks, nil
 56→}
