321→func parseTranscript(data []byte) (*kiroTranscript, error) {
322→	if len(data) == 0 {
323→		return &kiroTranscript{}, nil
324→	}
325→
326→	var transcript kiroTranscript
327→	if err := json.Unmarshal(data, &transcript); err != nil {
328→		return nil, fmt.Errorf("failed to parse kiro transcript: %w", err)
329→	}
330→	if isCLITranscript(&transcript) {
331→		return &transcript, nil
332→	}
333→
334→	if converted := tryParseIDETranscript(data); converted != nil {
335→		return converted, nil
336→	}
337→
338→	return &transcript, nil
339→}
