 25→	prodTrustedCommand  = "sh -c 'entire hooks *"
 26→	localDevCommandBase = "go run ${KIRO_PROJECT_DIR}/cmd/entire/main.go hooks kiro "
 27→	localDevTrustedCmd  = "sh -c 'go run ${KIRO_PROJECT_DIR}/cmd/entire/main.go hooks *"
 28→	prodHookCommandBase = "entire hooks kiro "
 29→	sessionIDFile       = "kiro-active-session"
 30→)
