432→func (a *Agent) generateAndCacheSessionID() string {
433→	sessionID := generateSessionID()
434→	cachePath := a.sessionIDCachePath()
435→	if err := os.MkdirAll(filepath.Dir(cachePath), 0o700); err == nil {
436→		_ = os.WriteFile(cachePath, []byte(sessionID), 0o600)
437→	}
438→	return sessionID
439→}
440→
441→func (a *Agent) readCachedSessionID() string {
442→	data, err := os.ReadFile(a.sessionIDCachePath())
443→	if err != nil {
444→		return ""
445→	}
446→	return strings.TrimSpace(string(data))
447→}
448→
449→func (a *Agent) clearCachedSessionID() {
450→	_ = os.Remove(a.sessionIDCachePath())
451→}
452→
453→func (a *Agent) sessionIDCachePath() string {
454→	return filepath.Join(protocol.RepoRoot(), ".entire", "tmp", sessionIDFile)
455→}
456→
457→func fallbackStopSessionID() string {
458→	return generateSessionID()
459→}
460→
461→func generateSessionID() string {
462→	buf := make([]byte, 16)
463→	if _, err := rand.Read(buf); err != nil {
464→		return fmt.Sprintf("kiro-%d", time.Now().UnixNano())
465→	}
466→	return hex.EncodeToString(buf)
467→}
