154→func runScenario(t *testing.T, s *RepoState, ctx context.Context, fn func(t *testing.T, s *RepoState, ctx context.Context)) (restarted bool) {
155→	t.Helper()
156→	defer func() {
157→		if r := recover(); r != nil {
158→			if _, ok := r.(errScenarioRestart); ok {
159→				restarted = true
160→				return
161→			}
162→			panic(r)
163→		}
164→	}()
165→	fn(t, s, ctx)
166→	return false
167→}
