133→func (a *Agent) ensureIDETranscript(cwd string, sessionID string) (string, error) {
134→	sessionsDir, err := ideWorkspaceSessionsDir(cwd)
135→	if err != nil {
136→		return "", err
137→	}
138→
139→	indexPath := filepath.Join(sessionsDir, "sessions.json")
140→	indexData, err := os.ReadFile(indexPath)
141→	if err != nil {
142→		return "", fmt.Errorf("IDE sessions.json not found: %w", err)
143→	}
144→
145→	var sessions []ideSessionIndexEntry
146→	if err := json.Unmarshal(indexData, &sessions); err != nil {
147→		return "", fmt.Errorf("failed to parse IDE sessions.json: %w", err)
148→	}
149→	if len(sessions) == 0 {
150→		return "", errors.New("no IDE sessions found")
151→	}
152→
153→	sort.Slice(sessions, func(i, j int) bool {
154→		return sessions[i].DateCreated > sessions[j].DateCreated
155→	})
156→
157→	ideSessionID := sessions[0].SessionID
158→	if !filepath.IsLocal(ideSessionID + ".json") {
159→		return "", fmt.Errorf("invalid session ID: %q", ideSessionID)
160→	}
161→
162→	transcriptPath := filepath.Join(sessionsDir, ideSessionID+".json")
163→	transcriptData, err := os.ReadFile(transcriptPath)
164→	if err != nil {
165→		return "", fmt.Errorf("failed to read IDE transcript %s: %w", transcriptPath, err)
166→	}
167→
168→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
169→	if err != nil {
170→		return "", err
171→	}
172→	if err := os.WriteFile(cachePath, transcriptData, 0o600); err != nil {
173→		return "", fmt.Errorf("failed to write cached IDE transcript: %w", err)
174→	}
175→	return cachePath, nil
176→}
