254→func allIDEHooksPresent(repoRoot string, localDev bool) bool {
255→	commandBase := hookCommandBase(localDev)
256→	for _, def := range ideHookDefs {
257→		path := filepath.Join(repoRoot, ".kiro", ideHooksDir, def.Filename+ideHookFileSuffix)
258→		data, err := os.ReadFile(path)
259→		if err != nil {
260→			return false
261→		}
262→		var hook kiroIDEHookFile
263→		if err := json.Unmarshal(data, &hook); err != nil {
264→			return false
265→		}
266→		if hook.Then.Command != shellWrappedCommand(commandBase+def.CLIVerb) {
267→			return false
268→		}
269→	}
270→	return true
271→}
272→
273→func trustedCommandsPresent(repoRoot string, localDev bool) bool {
274→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
275→	data, err := os.ReadFile(settingsPath)
276→	if err != nil {
277→		return false
278→	}
279→	var settings map[string]json.RawMessage
280→	if err := json.Unmarshal(data, &settings); err != nil {
281→		return false
282→	}
283→	raw, ok := settings[trustedCommandsKey]
284→	if !ok {
285→		return false
286→	}
287→	var commands []string
288→	if err := json.Unmarshal(raw, &commands); err != nil {
289→		return false
290→	}
291→	want := trustedCommand(localDev)
292→	for _, command := range commands {
293→		if command == want {
294→			return true
295→		}
296→	}
297→	return false
298→}
299→
300→func installTrustedCommands(repoRoot string, localDev bool) error {
301→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
302→
303→	settings, err := readSettings(settingsPath)
304→	if err != nil {
305→		return err
306→	}
307→	commands, err := readTrustedCommands(settings)
308→	if err != nil {
309→		return err
310→	}
311→	want := trustedCommand(localDev)
312→	for _, command := range commands {
313→		if command == want {
314→			return nil
315→		}
316→	}
317→	commands = append(commands, want)
318→	raw, err := json.Marshal(commands)
319→	if err != nil {
320→		return err
321→	}
322→	settings[trustedCommandsKey] = raw
323→	return writeSettings(settingsPath, settings)
324→}
325→
326→func uninstallTrustedCommands(repoRoot string) error {
327→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
328→	if _, err := os.Stat(settingsPath); err != nil {
329→		if os.IsNotExist(err) {
330→			return nil
331→		}
332→		return err
333→	}
334→	settings, err := readSettings(settingsPath)
335→	if err != nil {
336→		return err
337→	}
338→	commands, err := readTrustedCommands(settings)
339→	if err != nil {
340→		return err
341→	}
342→	filtered := commands[:0]
343→	for _, command := range commands {
344→		if command != prodTrustedCommand && command != localDevTrustedCmd {
345→			filtered = append(filtered, command)
346→		}
347→	}
348→	if len(filtered) == 0 {
349→		delete(settings, trustedCommandsKey)
350→	} else {
351→		raw, err := json.Marshal(filtered)
352→		if err != nil {
353→			return err
354→		}
355→		settings[trustedCommandsKey] = raw
356→	}
357→	return writeSettings(settingsPath, settings)
358→}
359→
360→func hookCommandBase(localDev bool) string {
361→	if localDev {
362→		return localDevCommandBase
363→	}
364→	return prodHookCommandBase
365→}
366→
367→// shellWrappedCommand wraps a hook command in "sh -c" with a /dev/null stdin
368→// redirect. IDEs typically run hook commands directly without a shell, so a
369→// bare "</dev/null" suffix is passed as a literal argument instead of being
370→// interpreted as a redirect. Wrapping in sh ensures the redirect works.
371→// The command content is built from compile-time constants (not user input).
372→func shellWrappedCommand(cmd string) string {
373→	return "sh -c '" + cmd + " </dev/null'"
374→}
375→
376→func trustedCommand(localDev bool) string {
377→	if localDev {
378→		return localDevTrustedCmd
379→	}
380→	return prodTrustedCommand
381→}
382→
383→func readSettings(path string) (map[string]json.RawMessage, error) {
384→	data, err := os.ReadFile(path)
385→	if err != nil {
386→		if os.IsNotExist(err) {
387→			return map[string]json.RawMessage{}, nil
388→		}
389→		return nil, err
390→	}
391→	var settings map[string]json.RawMessage
392→	if err := json.Unmarshal(data, &settings); err != nil {
393→		return nil, err
394→	}
395→	if settings == nil {
396→		settings = map[string]json.RawMessage{}
397→	}
398→	return settings, nil
399→}
400→
401→func readTrustedCommands(settings map[string]json.RawMessage) ([]string, error) {
402→	raw, ok := settings[trustedCommandsKey]
403→	if !ok {
404→		return []string{}, nil
405→	}
406→	var commands []string
407→	if err := json.Unmarshal(raw, &commands); err != nil {
408→		return nil, err
409→	}
410→	return commands, nil
411→}
412→
413→func writeSettings(path string, settings map[string]json.RawMessage) error {
414→	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
415→		return err
416→	}
417→	data, err := marshalJSON(settings)
418→	if err != nil {
419→		return err
420→	}
421→	return os.WriteFile(path, data, 0o600)
422→}
423→
424→func marshalJSON(v any) ([]byte, error) {
425→	data, err := json.MarshalIndent(v, "", "  ")
426→	if err != nil {
427→		return nil, err
428→	}
429→	return append(data, '\n'), nil
430→}
