461→func generateSessionID() string {
462→	buf := make([]byte, 16)
463→	if _, err := rand.Read(buf); err != nil {
464→		return fmt.Sprintf("kiro-%d", time.Now().UnixNano())
465→	}
466→	return hex.EncodeToString(buf)
467→}
