 79→// WaitForCheckpoint polls until the checkpoint branch advances from its
 80→// initial state, or fails the test after timeout.
 81→func WaitForCheckpoint(t *testing.T, s *RepoState, timeout time.Duration) {
 82→	t.Helper()
 83→	deadline := time.Now().Add(timeout)
 84→	for time.Now().Before(deadline) {
 85→		after := GitOutput(t, s.Dir, "rev-parse", "entire/checkpoints/v1")
 86→		if after != s.CheckpointBefore {
 87→			return
 88→		}
 89→		time.Sleep(200 * time.Millisecond)
 90→	}
 91→	t.Fatalf("checkpoint branch did not advance within %s", timeout)
 92→}
