229→// WaitForSessionIdle polls the session state files in .git/entire-sessions/
230→// until no session has phase "active", or fails the test after timeout.
231→func WaitForSessionIdle(t *testing.T, dir string, timeout time.Duration) {
232→	t.Helper()
233→	stateDir := filepath.Join(dir, ".git", "entire-sessions")
234→	deadline := time.Now().Add(timeout)
235→	for time.Now().Before(deadline) {
236→		entries, err := os.ReadDir(stateDir)
237→		if err != nil {
238→			time.Sleep(200 * time.Millisecond)
239→			continue
240→		}
241→		anyActive := false
242→		for _, entry := range entries {
243→			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") || strings.HasSuffix(entry.Name(), ".tmp") {
244→				continue
245→			}
246→			data, err := os.ReadFile(filepath.Join(stateDir, entry.Name()))
247→			if err != nil {
248→				continue
249→			}
250→			var state struct {
251→				Phase string `json:"phase"`
252→			}
253→			if err := json.Unmarshal(data, &state); err != nil {
254→				continue
255→			}
256→			if state.Phase == "active" {
257→				anyActive = true
258→				break
259→			}
260→		}
261→		if !anyActive {
262→			return
263→		}
264→		time.Sleep(200 * time.Millisecond)
265→	}
266→	t.Fatalf("session(s) did not transition to idle within %s", timeout)
267→}
