300→func (a *Agent) ExtractSummary(path string) (string, bool, error) {
301→	transcript, err := readAndParseTranscript(path)
302→	if errors.Is(err, os.ErrNotExist) {
303→		return "", false, nil
304→	}
305→	if err != nil {
306→		return "", false, err
307→	}
308→
309→	summary := extractLastAssistantResponse(transcript.History)
310→	return summary, summary != "", nil
311→}
