313→func readAndParseTranscript(path string) (*kiroTranscript, error) {
314→	data, err := os.ReadFile(path)
315→	if err != nil {
316→		return nil, err
317→	}
318→	return parseTranscript(data)
319→}
320→
321→func parseTranscript(data []byte) (*kiroTranscript, error) {
322→	if len(data) == 0 {
323→		return &kiroTranscript{}, nil
324→	}
325→
326→	var transcript kiroTranscript
327→	if err := json.Unmarshal(data, &transcript); err != nil {
328→		return nil, fmt.Errorf("failed to parse kiro transcript: %w", err)
329→	}
330→	if isCLITranscript(&transcript) {
331→		return &transcript, nil
332→	}
333→
334→	if converted := tryParseIDETranscript(data); converted != nil {
335→		return converted, nil
336→	}
337→
338→	return &transcript, nil
339→}
340→
341→func isCLITranscript(transcript *kiroTranscript) bool {
342→	if len(transcript.History) == 0 {
343→		return false
344→	}
345→	return len(transcript.History[0].User.Content) > 0 || len(transcript.History[0].Assistant) > 0
346→}
347→
348→func tryParseIDETranscript(data []byte) *kiroTranscript {
349→	var ide kiroIDETranscript
350→	if err := json.Unmarshal(data, &ide); err != nil {
351→		return nil
352→	}
353→	if len(ide.History) == 0 || ide.History[0].Message.Role == "" {
354→		return nil
355→	}
356→	return convertIDETranscript(&ide)
357→}
358→
359→func convertIDETranscript(ide *kiroIDETranscript) *kiroTranscript {
360→	transcript := &kiroTranscript{}
361→
362→	var pendingUser *kiroIDEHistoryEntry
363→	for i := range ide.History {
364→		entry := &ide.History[i]
365→		switch entry.Message.Role {
366→		case "user":
367→			if pendingUser != nil {
368→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
369→			}
370→			pendingUser = entry
371→		case "assistant":
372→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
373→			pendingUser = nil
374→		}
375→	}
376→
377→	if pendingUser != nil {
378→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
379→	}
380→
381→	return transcript
382→}
383→
384→func ideEntryToPaired(user, assistant *kiroIDEHistoryEntry) kiroHistoryEntry {
385→	entry := kiroHistoryEntry{}
386→
387→	if user != nil {
388→		prompt := extractIDEText(user.Message.Content, true)
389→		if prompt != "" {
390→			content, err := json.Marshal(kiroPromptContent{
391→				Prompt: struct {
392→					Prompt string `json:"prompt"`
393→				}{Prompt: prompt},
394→			})
395→			if err == nil {
396→				entry.User.Content = content
397→			}
398→		} else {
399→			entry.User.Content = user.Message.Content
400→		}
401→	}
402→
403→	if assistant != nil {
404→		text := extractIDEText(assistant.Message.Content, false)
405→		if text != "" {
406→			content, err := json.Marshal(kiroResponseContent{
407→				Response: kiroResponsePayload{Content: text},
408→			})
409→			if err == nil {
410→				entry.Assistant = content
411→			}
412→		} else {
413→			entry.Assistant = assistant.Message.Content
414→		}
415→	}
416→
417→	return entry
418→}
419→
420→// extractIDEText extracts text from a json.RawMessage that may be either a
421→// plain string or an array of content blocks. When blocksFirst is true, it
422→// tries to parse as blocks before falling back to a plain string (user
423→// messages); otherwise it tries plain string first (assistant messages).
424→func extractIDEText(content json.RawMessage, blocksFirst bool) string {
425→	if len(content) == 0 {
426→		return ""
427→	}
428→
429→	tryBlocks := func() string {
430→		var blocks []kiroIDEContentBlock
431→		if err := json.Unmarshal(content, &blocks); err == nil && len(blocks) > 0 {
432→			for _, block := range blocks {
433→				if block.Type == "text" && block.Text != "" {
434→					return block.Text
435→				}
436→			}
437→		}
438→		return ""
439→	}
440→
441→	tryString := func() string {
442→		var text string
443→		if err := json.Unmarshal(content, &text); err == nil {
444→			return text
445→		}
446→		return ""
447→	}
448→
449→	if blocksFirst {
450→		if s := tryBlocks(); s != "" {
451→			return s
452→		}
453→		return tryString()
454→	}
455→	if s := tryString(); s != "" {
456→		return s
457→	}
458→	return tryBlocks()
459→}
460→
461→func extractUserPrompt(content json.RawMessage) string {
462→	if len(content) == 0 {
463→		return ""
464→	}
465→
466→	var promptContent kiroPromptContent
467→	if err := json.Unmarshal(content, &promptContent); err == nil && promptContent.Prompt.Prompt != "" {
468→		return promptContent.Prompt.Prompt
469→	}
470→	return ""
471→}
472→
473→func extractModifiedFilesFromHistory(entries []kiroHistoryEntry) []string {
474→	seen := make(map[string]bool)
475→	var files []string
476→
477→	for i := range entries {
478→		for _, path := range extractFilesFromAssistant(entries[i].Assistant) {
479→			if path == "" || seen[path] {
480→				continue
481→			}
482→			seen[path] = true
483→			files = append(files, path)
484→		}
485→	}
486→
487→	return files
488→}
489→
490→func extractFilesFromAssistant(raw json.RawMessage) []string {
491→	if len(raw) == 0 {
492→		return nil
493→	}
494→
495→	var toolUseContent kiroToolUseContent
496→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
497→		return nil
498→	}
499→
500→	var paths []string
501→	for _, call := range toolUseContent.ToolUse.ToolUses {
502→		if !isFileModificationTool(call.Name) {
503→			continue
504→		}
505→		if path := extractFilePath(call.Args); path != "" {
506→			paths = append(paths, path)
507→		}
508→	}
509→	return paths
510→}
511→
512→func isFileModificationTool(name string) bool {
513→	_, ok := kiroFileModificationTools[name]
514→	return ok
515→}
516→
517→func extractFilePath(args json.RawMessage) string {
518→	if len(args) == 0 {
519→		return ""
520→	}
521→
522→	var fields map[string]json.RawMessage
523→	if err := json.Unmarshal(args, &fields); err != nil {
524→		return ""
525→	}
526→
527→	for _, key := range []string{"path", "file_path", "filename"} {
528→		raw, ok := fields[key]
529→		if !ok {
530→			continue
531→		}
532→		var path string
533→		if err := json.Unmarshal(raw, &path); err == nil && path != "" {
534→			return path
535→		}
536→	}
537→	return ""
538→}
539→
540→func extractLastAssistantResponse(entries []kiroHistoryEntry) string {
541→	for i := len(entries) - 1; i >= 0; i-- {
542→		if len(entries[i].Assistant) == 0 {
543→			continue
544→		}
545→
546→		var responseContent kiroResponseContent
547→		if err := json.Unmarshal(entries[i].Assistant, &responseContent); err == nil && responseContent.Response.Content != "" {
548→			return responseContent.Response.Content
549→		}
550→	}
551→	return ""
552→}
