105→func (a *Agent) InstallHooks(localDev bool, force bool) (int, error) {
106→	repoRoot := protocol.RepoRoot()
107→	if !force && allHooksInstalled(repoRoot, localDev) && trustedCommandsPresent(repoRoot, localDev) {
108→		return 0, nil
109→	}
110→
111→	if err := writeCLIHooks(repoRoot, localDev); err != nil {
112→		return 0, err
113→	}
114→	if err := writeIDEHooks(repoRoot, localDev); err != nil {
115→		return 0, err
116→	}
117→	if err := installTrustedCommands(repoRoot, localDev); err != nil {
118→		return 0, err
119→	}
120→
121→	return len(defaultHookNames()) + len(ideHookDefs), nil
122→}
