124→func (a *Agent) UninstallHooks() error {
125→	repoRoot := protocol.RepoRoot()
126→	cliPath := filepath.Join(repoRoot, ".kiro", hooksDir, hooksFileName)
127→	if err := os.Remove(cliPath); err != nil && !os.IsNotExist(err) {
