132→		if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
133→			return err
134→		}
135→	}
136→	if err := uninstallTrustedCommands(repoRoot); err != nil {
137→		return err
138→	}
139→	return nil
140→}
