193→func writeIDEHooks(repoRoot string, localDev bool) error {
194→	dir := filepath.Join(repoRoot, ".kiro", ideHooksDir)
195→	if err := os.MkdirAll(dir, 0o700); err != nil {
196→		return err
197→	}
198→	commandBase := hookCommandBase(localDev)
199→
200→	for _, def := range ideHookDefs {
201→		hook := kiroIDEHookFile{
202→			Enabled:     true,
203→			Name:        def.Filename,
204→			Description: "Entire CLI " + def.TriggerType + " hook",
205→			Version:     ideHookVersion,
206→			When: kiroIDEHookWhen{
207→				Type: def.TriggerType,
208→			},
209→			Then: kiroIDEHookThen{
210→				Type:    "runCommand",
211→				Command: shellWrappedCommand(commandBase + def.CLIVerb),
212→			},
213→		}
214→		data, err := marshalJSON(hook)
215→		if err != nil {
216→			return err
217→		}
218→		path := filepath.Join(dir, def.Filename+ideHookFileSuffix)
219→		if err := os.WriteFile(path, data, 0o600); err != nil {
220→			return err
221→		}
222→	}
223→
224→	return nil
