227→func allHooksInstalled(repoRoot string, localDev bool) bool {
228→	cliPath := filepath.Join(repoRoot, ".kiro", hooksDir, hooksFileName)
229→	commandBase := hookCommandBase(localDev)
230→	if data, err := os.ReadFile(cliPath); err == nil {
231→		var file kiroAgentFile
232→		if json.Unmarshal(data, &file) == nil &&
233→			hookCommandExists(file.Hooks.AgentSpawn, commandBase+HookNameAgentSpawn) &&
234→			hookCommandExists(file.Hooks.UserPromptSubmit, commandBase+HookNameUserPromptSubmit) &&
235→			hookCommandExists(file.Hooks.PreToolUse, commandBase+HookNamePreToolUse) &&
236→			hookCommandExists(file.Hooks.PostToolUse, commandBase+HookNamePostToolUse) &&
237→			hookCommandExists(file.Hooks.Stop, commandBase+HookNameStop) &&
238→			allIDEHooksPresent(repoRoot, localDev) {
239→			return true
240→		}
241→	}
242→	return false
243→}
