254→func allIDEHooksPresent(repoRoot string, localDev bool) bool {
255→	commandBase := hookCommandBase(localDev)
256→	for _, def := range ideHookDefs {
257→		path := filepath.Join(repoRoot, ".kiro", ideHooksDir, def.Filename+ideHookFileSuffix)
258→		data, err := os.ReadFile(path)
259→		if err != nil {
260→			return false
261→		}
262→		var hook kiroIDEHookFile
263→		if err := json.Unmarshal(data, &hook); err != nil {
264→			return false
265→		}
266→		if hook.Then.Command != shellWrappedCommand(commandBase+def.CLIVerb) {
267→			return false
268→		}
269→	}
270→	return true
