273→func trustedCommandsPresent(repoRoot string, localDev bool) bool {
274→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
275→	data, err := os.ReadFile(settingsPath)
276→	if err != nil {
277→		return false
278→	}
279→	var settings map[string]json.RawMessage
280→	if err := json.Unmarshal(data, &settings); err != nil {
281→		return false
282→	}
283→	raw, ok := settings[trustedCommandsKey]
284→	if !ok {
285→		return false
286→	}
287→	var commands []string
288→	if err := json.Unmarshal(raw, &commands); err != nil {
289→		return false
290→	}
291→	want := trustedCommand(localDev)
292→	for _, command := range commands {
293→		if command == want {
294→			return true
295→		}
296→	}
297→	return false
298→}
299→
300→func installTrustedCommands(repoRoot string, localDev bool) error {
301→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
302→
303→	settings, err := readSettings(settingsPath)
304→	if err != nil {
305→		return err
306→	}
307→	commands, err := readTrustedCommands(settings)
308→	if err != nil {
309→		return err
310→	}
311→	want := trustedCommand(localDev)
312→	for _, command := range commands {
313→		if command == want {
314→			return nil
315→		}
316→	}
317→	commands = append(commands, want)
318→	raw, err := json.Marshal(commands)
319→	if err != nil {
320→		return err
321→	}
322→	settings[trustedCommandsKey] = raw
323→	return writeSettings(settingsPath, settings)
324→}
325→
326→func uninstallTrustedCommands(repoRoot string) error {
327→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
328→	if _, err := os.Stat(settingsPath); err != nil {
329→		if os.IsNotExist(err) {
330→			return nil
331→		}
332→		return err
333→	}
334→	settings, err := readSettings(settingsPath)
335→	if err != nil {
336→		return err
337→	}
338→	commands, err := readTrustedCommands(settings)
339→	if err != nil {
340→		return err
341→	}
342→	filtered := commands[:0]
343→	for _, command := range commands {
344→		if command != prodTrustedCommand && command != localDevTrustedCmd {
345→			filtered = append(filtered, command)
346→		}
347→	}
348→	if len(filtered) == 0 {
349→		delete(settings, trustedCommandsKey)
350→	} else {
351→		raw, err := json.Marshal(filtered)
352→		if err != nil {
353→			return err
354→		}
355→		settings[trustedCommandsKey] = raw
356→	}
357→	return writeSettings(settingsPath, settings)
358→}
