		sessionID := a.readCachedSessionID()
		if sessionID == "" {
			nativeSessionID, err := a.querySessionID(cwd)
			if err == nil && nativeSessionID != "" {
				sessionID = nativeSessionID
			} else {
				sessionID = fallbackStopSessionID()
			}
