		sessionRef := a.captureTranscriptForStop(cwd, sessionID)
		a.clearCachedSessionID()
		return &protocol.EventJSON{
			Type:       3,
			SessionID:  sessionID,
			SessionRef: sessionRef,
			Timestamp:  time.Now().UTC().Format(time.RFC3339),
		}, nil
	default:
		return nil, nil
	}
