			pendingUser = nil
		}
	}

	if pendingUser != nil {
		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
	}

	return transcript
}

func ideEntryToPaired(user, assistant *kiroIDEHistoryEntry) kiroHistoryEntry {
