// filterTranscriptByStartTime parses the raw transcript and trims history
// entries that predate the cached session start time. This prevents cumulative
// kiro conversations from including turns that were already checkpointed.
// Returns the re-serialized JSON and true if filtering was applied, or
// (nil, false) if no filtering was needed or parsing failed.
func (a *Agent) filterTranscriptByStartTime(raw []byte) ([]byte, bool) {
	startTime := a.readCachedSessionStartTime()
	if startTime.IsZero() {
		return nil, false
	}

	parsed, err := parseTranscript(raw)
	if err != nil || len(parsed.History) == 0 {
		return nil, false
	}

	trimFrom := 0
	for i, entry := range parsed.History {
		if entry.User.Timestamp == "" {
			continue
