// buildTimestampedTranscript creates a kiro CLI transcript with entries at known timestamps.
func buildTimestampedTranscript(convID string, timestamps []time.Time) []byte {
	var entries []kiroHistoryEntry
	for _, ts := range timestamps {
		promptJSON, _ := json.Marshal(kiroPromptContent{
			Prompt: struct {
				Prompt string `json:"prompt"`
			}{Prompt: fmt.Sprintf("prompt at %s", ts.Format(time.RFC3339))},
		})
		entries = append(entries, kiroHistoryEntry{
			User: kiroUserMessage{
				Content:   promptJSON,
				Timestamp: ts.Format(time.RFC3339Nano),
			},
		})
		// Add a tool result entry (no timestamp) after each prompt.
		entries = append(entries, kiroHistoryEntry{
			User: kiroUserMessage{Content: json.RawMessage(`{"ToolUseResults":{}}`)},
		})
	}
	transcript := kiroTranscript{ConversationID: convID, History: entries}
	data, _ := json.Marshal(transcript)
	return data
}

