	repoRoot := t.TempDir()
	home := t.TempDir()
	t.Setenv("ENTIRE_REPO_ROOT", repoRoot)
	t.Setenv("HOME", home)

	base := time.Date(2026, 3, 20, 22, 0, 0, 0, time.UTC)
	timestamps := []time.Time{
		base,                          // entry 0: prompt
		base.Add(10 * time.Second),    // entry 2: prompt
		base.Add(20 * time.Second),    // entry 4: prompt
		base.Add(30 * time.Second),    // entry 6: prompt
	}
