 46→func (a *Agent) ParseHook(hookName string, input []byte) (*protocol.EventJSON, error) {
 47→	var raw hookInputRaw
 48→	if len(input) > 0 {
 49→		if err := json.Unmarshal(input, &raw); err != nil {
 50→			return nil, err
 51→		}
 52→	}
 53→
 54→	switch hookName {
 55→	case HookNameAgentSpawn:
 56→		sessionID := a.generateAndCacheSessionID()
 57→		a.cacheSessionStartTime()
 58→		return &protocol.EventJSON{
 59→			Type:      1,
 60→			SessionID: sessionID,
 61→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 62→		}, nil
 63→	case HookNameUserPromptSubmit:
 64→		sessionID := a.readCachedSessionID()
 65→		if sessionID == "" {
 66→			sessionID = a.generateAndCacheSessionID()
 67→		}
 68→		prompt := raw.Prompt
 69→		if prompt == "" {
 70→			prompt = os.Getenv("USER_PROMPT")
 71→		}
 72→		return &protocol.EventJSON{
 73→			Type:      2,
 74→			SessionID: sessionID,
 75→			Prompt:    prompt,
 76→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 77→		}, nil
 78→	case HookNamePreToolUse, HookNamePostToolUse:
 79→		return nil, nil
 80→	case HookNameStop:
 81→		cwd := raw.CWD
 82→		if cwd == "" {
 83→			cwd = protocol.RepoRoot()
 84→		}
 85→		sessionID := a.readCachedSessionID()
 86→		conversationID, _ := a.querySessionID(cwd)
 87→		if sessionID == "" {
 88→			if conversationID != "" {
 89→				sessionID = conversationID
 90→			} else {
 91→				sessionID = fallbackStopSessionID()
 92→			}
 93→		}
 94→		sessionRef := a.captureTranscriptForStop(cwd, sessionID, conversationID)
 95→		a.clearCachedSessionID()
 96→		return &protocol.EventJSON{
 97→			Type:       3,
 98→			SessionID:  sessionID,
 99→			SessionRef: sessionRef,
100→			Timestamp:  time.Now().UTC().Format(time.RFC3339),
101→		}, nil
102→	default:
103→		return nil, nil
104→	}
105→}
