302→func installTrustedCommands(repoRoot string, localDev bool) error {
303→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
304→
305→	settings, err := readSettings(settingsPath)
306→	if err != nil {
307→		return err
308→	}
309→	commands, err := readTrustedCommands(settings)
310→	if err != nil {
311→		return err
312→	}
313→	want := trustedCommand(localDev)
314→	for _, command := range commands {
315→		if command == want {
316→			return nil
317→		}
318→	}
319→	commands = append(commands, want)
320→	raw, err := json.Marshal(commands)
321→	if err != nil {
322→		return err
323→	}
324→	settings[trustedCommandsKey] = raw
325→	return writeSettings(settingsPath, settings)
326→}
