328→func uninstallTrustedCommands(repoRoot string) error {
329→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
330→	if _, err := os.Stat(settingsPath); err != nil {
331→		if os.IsNotExist(err) {
332→			return nil
333→		}
334→		return err
335→	}
336→	settings, err := readSettings(settingsPath)
337→	if err != nil {
338→		return err
339→	}
340→	commands, err := readTrustedCommands(settings)
341→	if err != nil {
342→		return err
343→	}
344→	filtered := commands[:0]
345→	for _, command := range commands {
346→		if command != prodTrustedCommand && command != localDevTrustedCmd {
347→			filtered = append(filtered, command)
348→		}
349→	}
350→	if len(filtered) == 0 {
351→		delete(settings, trustedCommandsKey)
352→	} else {
353→		raw, err := json.Marshal(filtered)
354→		if err != nil {
355→			return err
356→		}
357→		settings[trustedCommandsKey] = raw
358→	}
359→	return writeSettings(settingsPath, settings)
360→}
