369→// shellWrappedCommand wraps a hook command in "sh -c" with a /dev/null stdin
370→// redirect. IDEs typically run hook commands directly without a shell, so a
371→// bare "</dev/null" suffix is passed as a literal argument instead of being
372→// interpreted as a redirect. Wrapping in sh ensures the redirect works.
373→// The command content is built from compile-time constants (not user input).
374→func shellWrappedCommand(cmd string) string {
375→	return "sh -c '" + cmd + " </dev/null'"
376→}
