 63→func (a *Agent) querySessionID(cwd string) (string, error) {
 64→	db, err := kiroCLIDataDBPath()
 65→	if err != nil {
 66→		return "", err
 67→	}
 68→	if _, err := os.Stat(db); err != nil {
 69→		return "", fmt.Errorf("kiro database not found at %s: %w", db, err)
 70→	}
 71→
 72→	query := fmt.Sprintf(
 73→		"SELECT json_extract(value, '$.conversation_id') FROM conversations_v2 WHERE key = '%s' ORDER BY updated_at DESC LIMIT 1",
 74→		escapeSQLString(cwd),
 75→	)
 76→
 77→	out, err := runSQLiteCommand("-json", db, query)
 78→	if err != nil {
 79→		return "", fmt.Errorf("sqlite3 query failed: %w", err)
 80→	}
 81→
 82→	result := strings.TrimSpace(string(out))
 83→	if result == "" || result == "[]" {
 84→		return "", nil
 85→	}
 86→
 87→	var rows []map[string]string
 88→	if err := json.Unmarshal([]byte(result), &rows); err != nil {
 89→		return "", fmt.Errorf("failed to parse sqlite3 output: %w", err)
 90→	}
 91→	if len(rows) == 0 {
 92→		return "", nil
 93→	}
 94→	for _, value := range rows[0] {
 95→		return value, nil
 96→	}
 97→	return "", nil
 98→}
