100→func (a *Agent) ensureCachedTranscript(cwd string, sessionID string, conversationID string) (string, error) {
101→	db, err := kiroCLIDataDBPath()
102→	if err != nil {
103→		return "", err
104→	}
105→	if _, err := os.Stat(db); err != nil {
106→		return "", fmt.Errorf("kiro database not found at %s: %w", db, err)
107→	}
108→
109→	var query string
110→	if conversationID != "" {
111→		query = fmt.Sprintf(
112→			"SELECT value FROM conversations_v2 WHERE json_extract(value, '$.conversation_id') = '%s' ORDER BY updated_at DESC LIMIT 1",
113→			escapeSQLString(conversationID),
114→		)
115→	} else {
116→		query = fmt.Sprintf(
117→			"SELECT value FROM conversations_v2 WHERE key = '%s' ORDER BY updated_at DESC LIMIT 1",
118→			escapeSQLString(cwd),
119→		)
120→	}
121→
122→	out, err := runSQLiteCommand(db, query)
123→	if err != nil {
124→		return "", fmt.Errorf("sqlite3 transcript query failed: %w", err)
125→	}
126→
127→	raw := strings.TrimSpace(string(out))
128→	if raw == "" {
129→		return "", errors.New("no transcript found")
130→	}
131→
132→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
133→	if err != nil {
134→		return "", err
135→	}
136→
137→	data := []byte(raw)
138→	if filtered, ok := a.filterTranscriptByStartTime([]byte(raw)); ok {
139→		data = filtered
140→	}
141→
142→	if err := os.WriteFile(cachePath, data, 0o600); err != nil {
143→		return "", fmt.Errorf("failed to write cached transcript: %w", err)
144→	}
145→	return cachePath, nil
146→}
147→
148→// filterTranscriptByStartTime parses the raw transcript and trims history
149→// entries that predate the cached session start time. This prevents cumulative
150→// kiro conversations from including turns that were already checkpointed.
151→// Returns the re-serialized JSON and true if filtering was applied, or
152→// (nil, false) if no filtering was needed or parsing failed.
153→func (a *Agent) filterTranscriptByStartTime(raw []byte) ([]byte, bool) {
154→	startTime := a.readCachedSessionStartTime()
155→	if startTime.IsZero() {
156→		return nil, false
157→	}
158→
159→	parsed, err := parseTranscript(raw)
160→	if err != nil || len(parsed.History) == 0 {
161→		return nil, false
162→	}
163→
164→	trimFrom := 0
165→	for i, entry := range parsed.History {
166→		if entry.User.Timestamp == "" {
167→			continue
168→		}
169→		ts, err := time.Parse(time.RFC3339Nano, entry.User.Timestamp)
170→		if err != nil {
171→			continue
172→		}
173→		if !ts.Before(startTime) {
174→			trimFrom = i
175→			break
176→		}
177→	}
178→
179→	if trimFrom == 0 {
180→		return nil, false
181→	}
182→
183→	parsed.History = parsed.History[trimFrom:]
184→	filtered, err := json.Marshal(parsed)
185→	if err != nil {
186→		return nil, false
187→	}
188→	return filtered, true
189→}
