191→func (a *Agent) ensureIDETranscript(cwd string, sessionID string) (string, error) {
192→	sessionsDir, err := ideWorkspaceSessionsDir(cwd)
193→	if err != nil {
194→		return "", err
195→	}
196→
197→	indexPath := filepath.Join(sessionsDir, "sessions.json")
198→	indexData, err := os.ReadFile(indexPath)
199→	if err != nil {
200→		return "", fmt.Errorf("IDE sessions.json not found: %w", err)
201→	}
202→
203→	var sessions []ideSessionIndexEntry
204→	if err := json.Unmarshal(indexData, &sessions); err != nil {
205→		return "", fmt.Errorf("failed to parse IDE sessions.json: %w", err)
206→	}
207→	if len(sessions) == 0 {
208→		return "", errors.New("no IDE sessions found")
209→	}
210→
211→	sort.Slice(sessions, func(i, j int) bool {
212→		return sessions[i].DateCreated > sessions[j].DateCreated
213→	})
214→
215→	ideSessionID := sessions[0].SessionID
216→	if !filepath.IsLocal(ideSessionID + ".json") {
217→		return "", fmt.Errorf("invalid session ID: %q", ideSessionID)
218→	}
219→
220→	transcriptPath := filepath.Join(sessionsDir, ideSessionID+".json")
221→	transcriptData, err := os.ReadFile(transcriptPath)
222→	if err != nil {
223→		return "", fmt.Errorf("failed to read IDE transcript %s: %w", transcriptPath, err)
224→	}
225→
226→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
227→	if err != nil {
228→		return "", err
229→	}
230→	if err := os.WriteFile(cachePath, transcriptData, 0o600); err != nil {
231→		return "", fmt.Errorf("failed to write cached IDE transcript: %w", err)
232→	}
233→	return cachePath, nil
234→}
