379→func parseTranscript(data []byte) (*kiroTranscript, error) {
380→	if len(data) == 0 {
381→		return &kiroTranscript{}, nil
382→	}
383→
384→	var transcript kiroTranscript
385→	if err := json.Unmarshal(data, &transcript); err != nil {
386→		return nil, fmt.Errorf("failed to parse kiro transcript: %w", err)
387→	}
388→	if isCLITranscript(&transcript) {
389→		return &transcript, nil
390→	}
391→
392→	if converted := tryParseIDETranscript(data); converted != nil {
393→		return converted, nil
394→	}
395→
396→	return &transcript, nil
397→}
