399→func isCLITranscript(transcript *kiroTranscript) bool {
400→	if len(transcript.History) == 0 {
401→		return false
402→	}
403→	return len(transcript.History[0].User.Content) > 0 || len(transcript.History[0].Assistant) > 0
404→}
