406→func tryParseIDETranscript(data []byte) *kiroTranscript {
407→	var ide kiroIDETranscript
408→	if err := json.Unmarshal(data, &ide); err != nil {
409→		return nil
410→	}
411→	if len(ide.History) == 0 || ide.History[0].Message.Role == "" {
412→		return nil
413→	}
414→	return convertIDETranscript(&ide)
415→}
416→
417→func convertIDETranscript(ide *kiroIDETranscript) *kiroTranscript {
418→	transcript := &kiroTranscript{}
419→
420→	var pendingUser *kiroIDEHistoryEntry
421→	for i := range ide.History {
422→		entry := &ide.History[i]
423→		switch entry.Message.Role {
424→		case "user":
425→			if pendingUser != nil {
426→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
427→			}
428→			pendingUser = entry
429→		case "assistant":
430→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
431→			pendingUser = nil
432→		}
433→	}
434→
435→	if pendingUser != nil {
436→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
437→	}
438→
439→	return transcript
440→}
441→
442→func ideEntryToPaired(user, assistant *kiroIDEHistoryEntry) kiroHistoryEntry {
443→	entry := kiroHistoryEntry{}
444→
445→	if user != nil {
446→		prompt := extractIDEText(user.Message.Content, true)
447→		if prompt != "" {
448→			content, err := json.Marshal(kiroPromptContent{
449→				Prompt: struct {
450→					Prompt string `json:"prompt"`
451→				}{Prompt: prompt},
452→			})
453→			if err == nil {
454→				entry.User.Content = content
455→			}
456→		} else {
457→			entry.User.Content = user.Message.Content
458→		}
459→	}
460→
461→	if assistant != nil {
462→		text := extractIDEText(assistant.Message.Content, false)
463→		if text != "" {
464→			content, err := json.Marshal(kiroResponseContent{
465→				Response: kiroResponsePayload{Content: text},
466→			})
467→			if err == nil {
468→				entry.Assistant = content
469→			}
470→		} else {
471→			entry.Assistant = assistant.Message.Content
472→		}
473→	}
474→
475→	return entry
476→}
477→
478→// extractIDEText extracts text from a json.RawMessage that may be either a
479→// plain string or an array of content blocks. When blocksFirst is true, it
480→// tries to parse as blocks before falling back to a plain string (user
481→// messages); otherwise it tries plain string first (assistant messages).
482→func extractIDEText(content json.RawMessage, blocksFirst bool) string {
483→	if len(content) == 0 {
484→		return ""
485→	}
486→
487→	tryBlocks := func() string {
488→		var blocks []kiroIDEContentBlock
489→		if err := json.Unmarshal(content, &blocks); err == nil && len(blocks) > 0 {
490→			for _, block := range blocks {
491→				if block.Type == "text" && block.Text != "" {
492→					return block.Text
493→				}
494→			}
495→		}
496→		return ""
497→	}
498→
499→	tryString := func() string {
500→		var text string
501→		if err := json.Unmarshal(content, &text); err == nil {
502→			return text
503→		}
504→		return ""
505→	}
506→
507→	if blocksFirst {
508→		if s := tryBlocks(); s != "" {
509→			return s
510→		}
511→		return tryString()
512→	}
513→	if s := tryString(); s != "" {
514→		return s
515→	}
516→	return tryBlocks()
517→}
518→
519→func extractUserPrompt(content json.RawMessage) string {
520→	if len(content) == 0 {
521→		return ""
522→	}
523→
524→	var promptContent kiroPromptContent
525→	if err := json.Unmarshal(content, &promptContent); err == nil && promptContent.Prompt.Prompt != "" {
526→		return promptContent.Prompt.Prompt
527→	}
528→	return ""
529→}
