531→func extractModifiedFilesFromHistory(entries []kiroHistoryEntry) []string {
532→	seen := make(map[string]bool)
533→	var files []string
534→
535→	for i := range entries {
536→		for _, path := range extractFilesFromAssistant(entries[i].Assistant) {
537→			if path == "" || seen[path] {
538→				continue
539→			}
540→			seen[path] = true
541→			files = append(files, path)
542→		}
543→	}
544→
545→	return files
546→}
547→
548→func extractFilesFromAssistant(raw json.RawMessage) []string {
549→	if len(raw) == 0 {
550→		return nil
551→	}
552→
553→	var toolUseContent kiroToolUseContent
554→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
555→		return nil
556→	}
557→
558→	var paths []string
559→	for _, call := range toolUseContent.ToolUse.ToolUses {
560→		if !isFileModificationTool(call.Name) {
561→			continue
562→		}
563→		if path := extractFilePath(call.Args); path != "" {
564→			paths = append(paths, path)
565→		}
566→	}
567→	return paths
568→}
569→
570→func isFileModificationTool(name string) bool {
571→	_, ok := kiroFileModificationTools[name]
572→	return ok
573→}
574→
575→func extractFilePath(args json.RawMessage) string {
576→	if len(args) == 0 {
577→		return ""
578→	}
579→
580→	var fields map[string]json.RawMessage
581→	if err := json.Unmarshal(args, &fields); err != nil {
582→		return ""
583→	}
584→
585→	for _, key := range []string{"path", "file_path", "filename"} {
586→		raw, ok := fields[key]
587→		if !ok {
588→			continue
589→		}
590→		var path string
591→		if err := json.Unmarshal(raw, &path); err == nil && path != "" {
592→			return path
593→		}
594→	}
595→	return ""
596→}
597→
598→func extractLastAssistantResponse(entries []kiroHistoryEntry) string {
599→	for i := len(entries) - 1; i >= 0; i-- {
600→		if len(entries[i].Assistant) == 0 {
601→			continue
602→		}
603→
604→		var responseContent kiroResponseContent
605→		if err := json.Unmarshal(entries[i].Assistant, &responseContent); err == nil && responseContent.Response.Content != "" {
606→			return responseContent.Response.Content
607→		}
608→	}
609→	return ""
610→}
