588→// buildTimestampedTranscript creates a kiro CLI transcript with entries at known timestamps.
589→func buildTimestampedTranscript(convID string, timestamps []time.Time) []byte {
590→	var entries []kiroHistoryEntry
591→	for _, ts := range timestamps {
592→		promptJSON, _ := json.Marshal(kiroPromptContent{
593→			Prompt: struct {
594→				Prompt string `json:"prompt"`
595→			}{Prompt: fmt.Sprintf("prompt at %s", ts.Format(time.RFC3339))},
596→		})
597→		entries = append(entries, kiroHistoryEntry{
598→			User: kiroUserMessage{
599→				Content:   promptJSON,
600→				Timestamp: ts.Format(time.RFC3339Nano),
601→			},
602→		})
603→		// Add a tool result entry (no timestamp) after each prompt.
604→		entries = append(entries, kiroHistoryEntry{
605→			User: kiroUserMessage{Content: json.RawMessage(`{"ToolUseResults":{}}`)},
606→		})
607→	}
608→	transcript := kiroTranscript{ConversationID: convID, History: entries}
609→	data, _ := json.Marshal(transcript)
610→	return data
611→}
