func TestEnsureCachedTranscriptAllEntriesBeforeStartTime(t *testing.T) {
	repoRoot := t.TempDir()
	home := t.TempDir()
	t.Setenv("ENTIRE_REPO_ROOT", repoRoot)
	t.Setenv("HOME", home)

	base := time.Date(2026, 3, 20, 22, 0, 0, 0, time.UTC)
	transcriptData := buildTimestampedTranscript("conv-1", []time.Time{base, base.Add(10 * time.Second)})

	db := createFakeKiroDB(t, home)
	restore := stubSQLiteRunner(t, func(args ...string) ([]byte, error) {
		if args[0] != db {
			t.Fatalf("sqlite db = %q, want %q", args[0], db)
		}
		return transcriptData, nil
	})
	defer restore()

