// buildTimestampedTranscript creates a kiro CLI transcript with entries at known timestamps.
func buildTimestampedTranscript(convID string, timestamps []time.Time) []byte {
	var entries []kiroHistoryEntry
	for _, ts := range timestamps {
		promptJSON, _ := json.Marshal(kiroPromptContent{
			Prompt: struct {
				Prompt string `json:"prompt"`
			}{Prompt: fmt.Sprintf("prompt at %s", ts.Format(time.RFC3339))},
		})
		entries = append(entries, kiroHistoryEntry{
			User: kiroUserMessage{
				Content:   promptJSON,
				Timestamp: ts.Format(time.RFC3339Nano),
			},
		})
		// Add a tool result entry (no timestamp) after each prompt.
		entries = append(entries, kiroHistoryEntry{
			User: kiroUserMessage{Content: json.RawMessage(`{"ToolUseResults":{}}`)},
		})
	}
	transcript := kiroTranscript{ConversationID: convID, History: entries}
	data, _ := json.Marshal(transcript)
	return data
}

func seedSessionStartTime(t *testing.T, repoRoot string, ts time.Time) {
	t.Helper()
	cacheDir := filepath.Join(repoRoot, ".entire", "tmp")
	if err := os.MkdirAll(cacheDir, 0o750); err != nil {
		t.Fatalf("mkdir cache dir: %v", err)
	}
	if err := os.WriteFile(filepath.Join(cacheDir, sessionStartTimeFile), []byte(ts.UTC().Format(time.RFC3339Nano)), 0o600); err != nil {
		t.Fatalf("write session start time: %v", err)
	}
}

func TestEnsureCachedTranscriptFiltersByTimestamp(t *testing.T) {
	repoRoot := t.TempDir()
	home := t.TempDir()
	t.Setenv("ENTIRE_REPO_ROOT", repoRoot)
	t.Setenv("HOME", home)

	base := time.Date(2026, 3, 20, 22, 0, 0, 0, time.UTC)
	timestamps := []time.Time{
		base,                          // entry 0: prompt
		base.Add(10 * time.Second),    // entry 2: prompt
		base.Add(20 * time.Second),    // entry 4: prompt
		base.Add(30 * time.Second),    // entry 6: prompt
	}
	transcriptData := buildTimestampedTranscript("conv-1", timestamps)

	db := createFakeKiroDB(t, home)
	restore := stubSQLiteRunner(t, func(args ...string) ([]byte, error) {
		if args[0] != db {
			t.Fatalf("sqlite db = %q, want %q", args[0], db)
		}
		return transcriptData, nil
	})
	defer restore()

	// Set start time between entry 2 (T+10s) and entry 4 (T+20s).
	seedSessionStartTime(t, repoRoot, base.Add(15*time.Second))

	cachePath, err := New().ensureCachedTranscript(repoRoot, "test-session", "")
	if err != nil {
		t.Fatalf("ensureCachedTranscript() error = %v", err)
	}

	data, err := os.ReadFile(cachePath)
	if err != nil {
		t.Fatalf("read cached transcript: %v", err)
	}

	var result kiroTranscript
	if err := json.Unmarshal(data, &result); err != nil {
		t.Fatalf("parse cached transcript: %v", err)
	}

	// Should have entries from T+20s and T+30s (2 prompts + 2 tool results = 4 entries).
	if len(result.History) != 4 {
		t.Fatalf("history length = %d, want 4", len(result.History))
	}

	firstPrompt := extractUserPrompt(result.History[0].User.Content)
	if !strings.Contains(firstPrompt, "prompt at") || !strings.Contains(firstPrompt, "22:00:20") {
		t.Fatalf("first prompt = %q, expected T+20s prompt", firstPrompt)
	}
}

func TestEnsureCachedTranscriptAllEntriesBeforeStartTime(t *testing.T) {
	repoRoot := t.TempDir()
	home := t.TempDir()
	t.Setenv("ENTIRE_REPO_ROOT", repoRoot)
	t.Setenv("HOME", home)

	base := time.Date(2026, 3, 20, 22, 0, 0, 0, time.UTC)
